import{_ as a,o as r,c as o,ae as t}from"./chunks/framework.B6gjLfeO.js";const f=JSON.parse('{"title":"Analyze QR Code Performance","description":"","frontmatter":{"title":"Analyze QR Code Performance","slug":"analyze-qr-code-performance"},"headers":[],"relativePath":"marketer-hub/analyze-qr-code-performance.md","filePath":"marketer-hub/analyze-qr-code-performance.md"}'),n={name:"marketer-hub/analyze-qr-code-performance.md"};function s(c,e,i,l,h,d){return r(),o("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Explore Branch’s new linking experience for <a href="https://help.branch.io/docs/create-web-links-1#view-and-manage-links" target="_blank" rel="noreferrer">Web Links</a> and <a href="https://help.branch.io/docs/create-app-links-new" target="_blank" rel="noreferrer">App Links</a>, which offer deep linking, flexible configuration, and link analysis across multiple platforms!</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Branch Dashboard can help you generate and view reports for your QR Code campaigns.</p><p>The following metrics are specific to QR Codes. You can use them to view, compare, and filter your campaigns:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Description</th></tr></thead><tbody><tr><td>Link Title</td><td>The title of your QR Code.</td></tr><tr><td>Scans</td><td>Number of times users scanned on a Branch Link, or on an ad where Branch can fetch click data from a third party (e.g. Facebook ads).</td></tr></tbody></table><h2 id="analyze-qr-code-performance" tabindex="-1">Analyze QR Code Performance <a class="header-anchor" href="#analyze-qr-code-performance" aria-label="Permalink to &quot;Analyze QR Code Performance&quot;">​</a></h2><p>To start analyzing the performance of your Branch QR Codes, start by navigating to the <strong>Analytics</strong> <a href="https://dashboard.branch.io/qr-codes/analytics" target="_blank" rel="noreferrer">tab</a> of the QR Codes <a href="https://dashboard.branch.io/qr-codes" target="_blank" rel="noreferrer">section</a> of the Branch Dashboard.</p><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><p>Within the <strong>Analytics</strong> tab you&#39;ll find the <strong>Performance</strong> table, which allows you to view your Branch QR Code campaign performance through customizable tables with download capabilities.</p><h3 id="trends" tabindex="-1">Trends <a class="header-anchor" href="#trends" aria-label="Permalink to &quot;Trends&quot;">​</a></h3><p>Below the <strong>Performance</strong> table is the <strong>Trends</strong> graph, which allows you to view your Branch QR Code campaign performance through robust charts.</p><div class="tip custom-block"><p class="custom-block-title">More Reporting</p><p>QR Code reports are similar to other Branch Dashboard reports. To learn more, view our Dashboard Reports <a href="./dashboard-reports.html">guide</a>.</p></div>',12)])])}const m=a(n,[["render",s]]);export{f as __pageData,m as default};
